async def acceptFriendRequest(
    executor: gel.AsyncIOExecutor,
    *,
    request_id: uuid.UUID,
) -> acceptFriendRequestResult | None:
    return await executor.query_single(
        """\
        with
            request := assert_single(
                select FriendRequest
                filter .id = <uuid>$request_id
                    and .recipient.id = global current_user.id
            ),
            sender := request.sender,
            recipient := request.recipient
        insert Friend {
            user1 := sender,
            user2 := recipient
        }
        unless conflict on ((.user1, .user2))
        else (
            select Friend
            filter (.user1 = sender and .user2 = recipient)
                or (.user1 = recipient and .user2 = sender)
        );

        delete FriendRequest
        filter .id = <uuid>$request_id;\
        """,
        request_id=request_id,
    )


async def copyGraphicToDraft(
    executor: gel.AsyncIOExecutor,
    *,
    graphic_id: uuid.UUID,
) -> copyGraphicToDraftResult:
    return await executor.query_single(
        """\
        with
          user := assert_single(
            select User
            filter assert_single(.identity = global ext::auth::ClientTokenIdentity)
          ),
          source := assert_single(
            select PixelGraphic
            filter .id = <uuid>$graphic_id
          )
        insert DraftGraphic {
          creator := user,
          binary := source.binary,
          size := source.size,
          frames := source[is PixelAnimation].frames ?? 1,
          fps := source[is PixelAnimation].fps ?? 10
        }\
        """,
        graphic_id=graphic_id,
    )


async def copyGraphicToGallery(
    executor: gel.AsyncIOExecutor,
    *,
    graphic_id: uuid.UUID,
) -> copyGraphicToGalleryResult | None:
    return await executor.query_single(
        """\
        with
          user := assert_single(
            select User
            filter global ext::auth::ClientTokenIdentity in .identity
          ),
          source := assert_single(
            select PixelGraphic
            filter .id = <uuid>$graphic_id
          ),
          is_animation := source is PixelAnimation,
          new_graphic := (
            insert PixelAnimation {
              binary := source.binary,
              frames := source[is PixelAnimation].frames ?? <int16>1,
              fps := source[is PixelAnimation].fps ?? <int16>10,
              size := source.size,
              creator := user
            }
          ) if is_animation else (
            insert StaticImage {
              binary := source.binary,
              size := source.size,
              creator := user
            }
          )
        select new_graphic { id }\
        """,
        graphic_id=graphic_id,
    )


