async def insertMessage(
    executor: gel.AsyncIOExecutor,
    *,
    data: bytes,
    size: BoardType,
    recipient_id: uuid.UUID | None = None,
) -> deleteRecipientMessageResult:
    return await executor.query_single(
        """\
        with
          user := assert_single(
            select User
            filter assert_single(.identity = global ext::auth::ClientTokenIdentity)
          ),
          new_graphic := (
            insert StaticImage {
              binary := <bytes>$data,
              size := <BoardType>$size,
              creator := user
            }
          )
        insert Message {
          graphic := new_graphic,
          sender := user,
          recipient := (select User filter .id = <optional uuid>$recipient_id)
        }\
        """,
        data=data,
        size=size,
        recipient_id=recipient_id,
    )


